// api/sync-backlinks.js — Vercel Serverless Function
// Fetches live backlinks for serponado.io via DataForSEO, syncs to KV.
// Triggered by Vercel Cron (daily) or manually via ?secret=SYNC_SECRET.
// Each new domain gets a JARVIS comment generated by Claude.

const TARGET = 'serponado.io'

const SEED_DOMAINS = new Set(['till-freitag.com'])

function getTierFromRank(rank) {
  if (rank >= 60) return 'platinum'
  if (rank >= 35) return 'gold'
  if (rank >= 15) return 'silver'
  if (rank >= 5)  return 'bronze'
  return 'iron'
}

async function generateJarvisComment(domain, anchor, rank, anthropicKey) {
  if (!anthropicKey) return null
  try {
    const r = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': anthropicKey,
        'anthropic-version': '2023-06-01',
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        model: 'claude-sonnet-4-6',
        max_tokens: 120,
        system: `Du bist JARVIS. Bewerte einen eingehenden Backlink zu serponado.io in 1-2 prägnanten Sätzen. Ton: analytisch, leicht herablassend-amüsiert, niemals bösartig. Auf Deutsch. Keine Einleitung, direkt zur Bewertung.`,
        messages: [{ role: 'user', content: `Domain: ${domain} | Anchor: "${anchor}" | DataForSEO Rank: ${rank}/100` }],
      }),
    })
    const data = await r.json()
    return data?.content?.[0]?.text || null
  } catch {
    return null
  }
}

async function getKvLinks(kvUrl, kvToken) {
  try {
    const r = await fetch(`${kvUrl}/lrange/serponado:backlinks/0/-1`, {
      headers: { Authorization: `Bearer ${kvToken}` },
    })
    const { result } = await r.json()
    return (result || [])
      .map(e => { try { return JSON.parse(e) } catch { return null } })
      .filter(Boolean)
  } catch {
    return []
  }
}

async function pushKvLink(kvUrl, kvToken, entry) {
  await fetch(`${kvUrl}/rpush/serponado:backlinks/${encodeURIComponent(JSON.stringify(entry))}`, {
    headers: { Authorization: `Bearer ${kvToken}` },
  })
}

export default async function handler(req, res) {
  // Auth: Vercel CRON_SECRET (automatic) or manual SYNC_SECRET query param
  const cronSecret  = process.env.CRON_SECRET
  const syncSecret  = process.env.SYNC_SECRET
  const authHeader  = req.headers.authorization || ''

  const urlParams   = new URL(req.url, 'https://placeholder').searchParams
  const secretParam = urlParams.get('secret') || req.body?.secret || ''

  const isCron   = cronSecret && authHeader === `Bearer ${cronSecret}`
  const isManual = syncSecret && secretParam.trim() === syncSecret.trim()

  if (!isCron && !isManual) {
    return res.status(401).json({ error: 'Unauthorized', debug: { hasSync: !!syncSecret, hasCron: !!cronSecret, param: !!secretParam } })
  }

  const login        = process.env.DATAFORSEO_LOGIN
  const password     = process.env.DATAFORSEO_PASSWORD
  const kvUrl        = process.env.KV_REST_API_URL
  const kvToken      = process.env.KV_REST_API_TOKEN
  const anthropicKey = process.env.ANTHROPIC_API_KEY

  if (!login || !password) return res.status(500).json({ error: 'DATAFORSEO credentials missing' })
  if (!kvUrl  || !kvToken)  return res.status(500).json({ error: 'KV credentials missing' })

  // 1. Fetch backlinks from DataForSEO Live API
  const credentials = Buffer.from(`${login}:${password}`).toString('base64')
  let items = []
  try {
    const dfsRes = await fetch('https://api.dataforseo.com/v3/backlinks/backlinks/live', {
      method: 'POST',
      headers: {
        Authorization: `Basic ${credentials}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify([{
        target: TARGET,
        limit: 1000,
        include_subdomains: false,
        include_indirect_links: true,
        filters: ['dofollow', '=', true],
        order_by: ['domain_from_rank,desc'],
      }]),
    })
    const dfsData = await dfsRes.json()
    items = dfsData?.tasks?.[0]?.result?.[0]?.items || []
  } catch (e) {
    return res.status(502).json({ error: `DataForSEO error: ${e.message}` })
  }

  if (items.length === 0) {
    return res.status(200).json({ added: 0, message: 'No backlinks found yet in DataForSEO index.' })
  }

  // 2. Get existing domains from KV + seed
  const existing = await getKvLinks(kvUrl, kvToken)
  const knownDomains = new Set([
    ...SEED_DOMAINS,
    ...existing.map(l => l.domain),
  ])

  // 3. Deduplicate by domain_from, keep highest-ranked link per domain
  const byDomain = new Map()
  for (const item of items) {
    const domain = item.domain_from?.replace(/^www\./, '')
    if (!domain || knownDomains.has(domain)) continue
    const prev = byDomain.get(domain)
    if (!prev || item.domain_from_rank > prev.domain_from_rank) {
      byDomain.set(domain, item)
    }
  }

  // 4. Add new entries to KV with JARVIS comments
  const added = []
  for (const [domain, item] of byDomain) {
    const rank    = item.domain_from_rank || 0
    const tier    = getTierFromRank(rank)
    const anchor  = item.anchor || domain
    const comment = await generateJarvisComment(domain, anchor, rank, anthropicKey)

    const entry = {
      id:            `${domain}-${Date.now()}`,
      linkFrom:      item.url_from,
      domain,
      anchor,
      vi:            0,
      dfsRank:       rank,
      tier,
      addedAt:       new Date().toISOString().slice(0, 10),
      jarvisComment: comment,
      source:        'dataforseo-auto',
    }

    await pushKvLink(kvUrl, kvToken, entry)
    added.push(domain)
  }

  return res.status(200).json({
    scanned: items.length,
    newDomains: added.length,
    added,
  })
}
